import fs from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const scriptDir = path.dirname(fileURLToPath(import.meta.url));
const rootDir = path.resolve(scriptDir, "..");
const sourceDir = path.join(rootDir, "source_truth");
const manifestPath = path.join(sourceDir, "manifest.json");
const outputPath = path.join(rootDir, "source_truth_bundle.js");

const manifest = JSON.parse(await fs.readFile(manifestPath, "utf8"));
const files = [];

for (const entry of manifest.files || []) {
  const name = typeof entry === "string" ? entry : entry.name;
  const label = typeof entry === "string" ? entry : entry.label || entry.name;
  if (!name) continue;

  const fullPath = path.join(sourceDir, name);
  const text = await fs.readFile(fullPath, "utf8");
  files.push({ name, label, text });
}

const bundle = {
  version: 1,
  generatedAt: new Date().toISOString(),
  source: "source_truth/manifest.json",
  files,
};

const output = `// Generated by tools/build-source-truth-bundle.mjs.\n// This fallback lets source truth load when browser file/fetch access is restricted.\nwindow.JP_TRANSLATE_SOURCE_BUNDLE = ${JSON.stringify(bundle, null, 2)};\n`;

await fs.writeFile(outputPath, output, "utf8");
console.log(`Wrote ${path.relative(rootDir, outputPath)} with ${files.length} source truth files.`);
